struct FenwickTree {
    size: usize,
    tree: Vec<i64>,
}

impl FenwickTree {
    fn new(size: usize) -> Self {
        let tree = vec![0; size + 1];
        FenwickTree { size, tree }
    }

    fn update(&mut self, idx: usize, delta: i64) {
        let idx = idx + 1; // 1-based index
        while idx <= self.size {
            self.tree[idx] += delta;
            idx += idx & -idx;
        }
    }

    fn query(&self, idx: usize) -> i64 {
        let idx = idx + 1; // 1-based index
        let mut res = 0;
        while idx > 0 {
            res += self.tree[idx];
            idx -= idx & -idx;
        }
        res
    }

    fn range_query(&self, l: usize, r: usize) -> i64 {
        self.query(r) - self.query(l - 1)
    }
}

fn compute_depth(x: i64) -> i64 {
    let mut current = x;
    let mut depth = 0;
    while current != 1 {
        current = current.count_ones() as i64;
        depth += 1;
    }
    depth
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut ft = vec![FenwickTree::new(n); 6]; // for k=0 to 5

    // Precompute the depths and populate the Fenwick Trees
    for i in 0..n {
        let x = nums[i];
        let depth = compute_depth(x);
        if depth >= 0 && depth <= 5 {
            ft[depth as usize].update(i, 1);
        }
    }

    let mut answer = Vec::new();

    for q in queries {
        if q[0] == 1 {
            // query type 1: [1, l, r, k]
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            // check if k is within 0-5
            if k < 6 {
                let res = ft[k].range_query(l, r);
                answer.push(res);
            } else {
                // invalid k, but according to problem statement, k is up to 5
                answer.push(0);
            }
        } else {
            // query type 2: [2, idx, val]
            let idx = q[1] as usize;
            let val = q[2];
            // get old value
            let old_val = nums[idx];
            // compute old depth
            let old_depth = compute_depth(old_val);
            if old_depth >= 0 && old_depth <= 5 {
                ft[old_depth as usize].update(idx, -1);
            }
            // update the nums array
            nums[idx] = val;
            // compute new depth
            let new_depth = compute_depth(val);
            if new_depth >= 0 && new_depth <= 5 {
                ft[new_depth as usize].update(idx, 1);
            }
        }
    }

    answer
}
