impl FenwickTree {
    fn new(n: usize) -> Self {
        let mut tree = vec![0; n + 1]; // 1-based indexing
        FenwickTree { n, tree }
    }

    fn update(&mut self, idx: usize, delta: i64) {
        let idx = idx + 1; // convert to 1-based
        while idx <= self.n {
            self.tree[idx] += delta;
            idx += idx & -idx;
        }
    }

    fn query(&self, idx: usize) -> i64 {
        let idx = idx + 1; // convert to 1-based
        let mut sum = 0;
        while idx > 0 {
            sum += self.tree[idx];
            idx -= idx & -idx;
        }
        sum
    }

    fn range_query(&self, l: usize, r: usize) -> i64 {
        self.query(r) - self.query(l - 1)
    }
}

