fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    // Initialize 6 Fenwick Trees for k=0 to 5
    let mut fenwick_trees: Vec<FenwickTree> = vec![FenwickTree::new(n); 6];
    // Precompute the depth for each number
    for i in 0..n {
        let x = nums[i];
        let depth = get_depth(x);
        if depth <=5 {
            fenwick_trees[depth].update(i, 1);
        }
    }
    // Process queries
    let mut answer = Vec::new();
    for q in queries {
        if q[0] == 1 {
            // Type 1 query: [1, l, r, k]
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            if k < 0 || k >5 {
                answer.push(0);
                continue;
            }
            let res = fenwick_trees[k].range_query(l, r);
            answer.push(res);
        } else {
            // Type 2 query: [2, idx, val]
            let idx = q[1] as usize;
            let val = q[2];
            // Get old value and depth
            let old_val = nums[idx];
            let old_depth = get_depth(old_val);
            if old_depth <=5 {
                fenwick_trees[old_depth].update(idx, -1);
            }
            // Update the value
            nums[idx] = val;
            let new_depth = get_depth(val);
            if new_depth <=5 {
                fenwick_trees[new_depth].update(idx, 1);
            }
        }
    }
    answer
}

